import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class DataService {

  constructor() { }

  private messageSource = new BehaviorSubject("");
  sendMessage(msg: any){
    this.messageSource.next(msg);
  }
  getMessage(){
    return this.messageSource.asObservable();
  }
}
